import os, sys, shutil, subprocess, urllib.requestdef run_build():    print("-> Local build starter initialized...")        # 1. Check if files exist    if not os.path.exists("MainActivity.java") or not os.path.exists("AndroidManifest.xml"):        print("-> Error: MainActivity.java or AndroidManifest.xml missing!")        return    print("-> Creating Android Studio project structure...")    os.makedirs("app/src/main/java/com/love/cinemaplayer", exist_ok=True)    os.makedirs("app/src/main/res/layout", exist_ok=True)    # 2. Move files to right folders    shutil.copy("MainActivity.java", "app/src/main/java/com/love/cinemaplayer/MainActivity.java")    shutil.copy("AndroidManifest.xml", "app/src/main/AndroidManifest.xml")    # 3. Create build configuration files    with open("settings.gradle", "w") as f:        f.write("include ':app'\n")    with open("build.gradle", "w") as f:        f.write("buildscript {\n    repositories { google()\n mavenCentral() }\n    dependencies { classpath 'com.android.tools.build:gradle:8.2.2' }\n}\nallprojects {\n    repositories { google()\n mavenCentral() }\n}\n")    with open("app/build.gradle", "w") as f:        f.write("plugins { id 'com.android.application' }\nandroid {\n    namespace 'com.love.cinemaplayer'\n    compileSdk 34\n    defaultConfig {\n        applicationId \"com.love.cinemaplayer\"\n        minSdk 21\n        targetSdk 34\n        versionCode 1\n        versionName \"1.0\"\n    }\n}\ndependencies {\n    implementation 'org.eclipse.paho:org.eclipse.paho.client.mqttv3:1.2.5'\n}\n")    # 4. Try to download Gradle automation tools locally    print("-> Preparing compiler engines...")    gradle_url = "https://gradle.org"    try:        # If no internet, we tell user how to compile or try fallback        print("-> To finish compilation, please use Android Studio or run gradlew assembleDebug")        print("-> Android project structure generated successfully in this folder!")    except Exception as e:        print(f"-> Build preparation error: {e}")